#include<stdio.h>
int minfac(int y){
	int i;
	for(i=2;i*i<=y;i++){
		if(!(y%i)) return i;
	}
	return y;
}
int main(){
	int p,y,i,j=0;
	scanf("%d%d",&p,&y);
	while(j<=300){
		i=minfac(y);
		if(i>p){
			printf("%d\n",y);
			return 0;
		}
		j++;
		y--;
	}
	printf("-1\n");
	return 0;
}

