use std::io::Read;
fn main() {
    let mut buf = String::new();
    std::io::stdin().read_to_string(&mut buf).unwrap();
    let mut iter = buf.split_whitespace();
    let p: u32 = iter.next().unwrap().parse().unwrap();
    let y: u32 = iter.next().unwrap().parse().unwrap();
    for x in (p..(y+1)).rev() {
        if check(x, p) {
            println!("{}", x);
            return
        }
    }
    println!("{}", -1);
}

fn check(x : u32, p : u32) -> bool {
    for i in 2..(p+1) {
        if i*i>x {
            break;
        }
        if x%i==0 {
            return false;
        }
    }
    return !(x%p==0);
}
